using UnityEngine;

/// <summary>
/// Define um emblema mostrado na parte inferior da secção Progresso do Menu de
/// Pausa (Tarefa #11): "Emblema de Gaia; Emblema de Apolo; Emblema de Zeus;
/// emblemas dos seis mundos" (9 no total).
///
/// Estado visual (resolvido por ProgressSectionUI/EmblemNodeUI):
/// - Não obtido E "heardAboutVariable" falso (ou vazio) → mostra
///   <see cref="unknownIcon"/> ("marca de pedra desconhecida"), sem texto de
///   condição.
/// - Não obtido E "heardAboutVariable" verdadeiro → mostra
///   <see cref="unknownIcon"/> + <see cref="conditionDescription"/> ("Depois de
///   o jogador ouvir falar dele, a condição seria revelada").
/// - Obtido (variável "obtainedVariable" verdadeira) → mostra <see cref="icon"/>.
///
/// As variáveis referenciadas (heardAboutVariable/obtainedVariable) são bools
/// geridos por GameVariables, tal como MissionData usa StartedVariable/
/// CompletedVariable — reutiliza a infraestrutura de
/// Action_SetBoolVariable/Condition_BoolVariable já existente, sem novo estado
/// de save dedicado.
/// </summary>
[CreateAssetMenu(menuName = "Animals/Emblem Data", fileName = "NewEmblem")]
public class EmblemData : ScriptableObject
{
    [Header("Identidade")]
    public string emblemId;
    public string displayName;

    [Header("Mundo")]
    [Tooltip("Mundo a que este emblema pertence (um dos seis emblemas de mundo). Deixar vazio para os emblemas globais: Gaia, Apolo, Zeus.")]
    public WorldData world;

    [Header("Ícones")]
    [Tooltip("Ícone mostrado depois de o emblema ser obtido.")]
    public Sprite icon;

    [Tooltip("\"Marca de pedra desconhecida\" — ícone mostrado enquanto o emblema não foi obtido.")]
    public Sprite unknownIcon;

    [Header("Condição (Revelação)")]
    [Tooltip("Nome da variável bool (GameVariables) que indica que o jogador já ouviu falar deste emblema. Enquanto falsa/vazia, nenhuma condição é mostrada — apenas o ícone desconhecido.")]
    public string heardAboutVariable;

    [Tooltip("Texto da condição para obter este emblema, revelado depois de \"heardAboutVariable\" ficar verdadeira.")]
    [TextArea] public string conditionDescription;

    [Header("Obtenção")]
    [Tooltip("Nome da variável bool (GameVariables) que indica que o jogador obteve este emblema.")]
    public string obtainedVariable;

    [Header("Papel na Percentagem Total do Save")]
    [Tooltip("Emblema de Gaia: concedido ao atingir 100% (todo o conteúdo principal completo). NÃO entra no cálculo de % (seria circular). Em conjunto com 'isApoloEmblem', activa o resultado especial 101% — que por sua vez concede o Emblema de Zeus (Tarefa #31).")]
    public bool isGaiaEmblem;

    [Tooltip("Emblema de Apolo: concedido ao completar a Provação de Apolo (independente da %). NÃO entra no cálculo de %. Em conjunto com 'isGaiaEmblem', activa o resultado especial 101% (Tarefa #31).")]
    public bool isApoloEmblem;

    [Tooltip("Emblema bónus/secreto: não entra nem no numerador nem no denominador da percentagem total do save. Use para emblemas que não devem influenciar a % de conclusão (ex: Emblema de Zeus, que é dado pela própria regra Gaia+Apolo). isGaiaEmblem e isApoloEmblem implicam o mesmo comportamento de exclusão.")]
    public bool isBonus;
}
